<template><main class='page'><header class='page-header'><h1 class='page-title'>今日菜单</h1><p class='page-subtitle'>把选好的菜汇总成买菜清单，买完可以逐项勾选。</p></header><template v-if='cart.length'><article v-for='(item,index) in cart' :key='item.cartId||index' class='cart-item card'><img :src='item.image'/><div><h3>{{item.name}}</h3><p>{{item.cuisine}} · {{item.selectedSpec?.label}}</p><span>{{item.ingredients.join('、')}}</span></div><button @click='remove(index)'>删除</button></article><section class='summary card'><h2>买菜清单</h2><label v-for='item in ingredients' :key='item' class='check'><input type='checkbox' :checked='checked.includes(item)' @change='toggle(item)'/><span>{{item}}</span></label></section><section class='summary card'><h2>按菜品查看</h2><details v-for='item in cart' :key='item.cartId'><summary>{{item.name}}</summary><p>{{item.ingredients.join('、')}}</p></details></section><button class='danger-button clear' @click='handleClear'>清空今日菜单</button></template><div v-else class='empty'><span class='empty-icon'>🍽️</span><strong class='empty-title'>还没有选择菜品</strong><p>去首页或分类里挑几道今天想吃的菜。</p></div></main></template><script setup>import{computed,onMounted,ref}from'vue';import{clearCart,getCart,removeCartAt,getCheckedIngredients,setCheckedIngredients}from'../utils/storage';const cart=ref([]),checked=ref([]);onMounted(()=>{cart.value=getCart();checked.value=getCheckedIngredients()});const ingredients=computed(()=>[...new Set(cart.value.flatMap(x=>x.ingredients||[]))]);function remove(i){cart.value=removeCartAt(i)}function handleClear(){clearCart();cart.value=[];checked.value=[];setCheckedIngredients([])}function toggle(item){checked.value=checked.value.includes(item)?checked.value.filter(x=>x!==item):[...checked.value,item];setCheckedIngredients(checked.value)}</script><style scoped>.cart-item{display:flex;gap:13px;padding:12px;margin-bottom:14px;align-items:center}.cart-item img{width:86px;height:86px;border-radius:18px;object-fit:cover;background:#eee}.cart-item div{flex:1;min-width:0}.cart-item h3{margin:0;font-size:17px}.cart-item p{margin:6px 0;color:var(--blue);font-weight:900;font-size:13px}.cart-item span{display:-webkit-box;color:var(--sub);font-size:12px;line-height:1.45;overflow:hidden;-webkit-line-clamp:2;-webkit-box-orient:vertical}.cart-item button{border:0;color:var(--red);background:#fff0f0;border-radius:999px;padding:8px 10px;font-weight:900}.summary{padding:22px;margin-top:18px}.summary h2{margin:0 0 14px;font-size:20px}.check{display:flex;align-items:center;gap:10px;padding:11px 0;border-bottom:1px solid var(--line);font-weight:800}.check:last-child{border-bottom:0}.check input{width:20px;height:20px}details{padding:12px 0;border-bottom:1px solid var(--line)}summary{font-weight:900}details p{color:var(--sub);line-height:1.6}.clear{width:100%;margin-top:18px}</style>
